import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";

import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { introspectionTool } from "./tools/plugins/introspection";
import { sessionArchaeologyTool } from "./tools/plugins/session_archaeology";
import { ltmStoreTool, ltmQueryTool, ltmStatsTool, initializeLTM } from "./tools/plugins/ltm_tool";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Initialize LTM for persistent self-knowledge
  const sessionId = path.basename(memory.getSessionFile()).replace(".json", "");
  await initializeLTM("HELIOS", sessionId);

  // Register Plugins (Safe initialization)
  const shellReady = await tools.registerTool(shellPlugin);
  if (!shellReady) {
    console.error("FATAL: Essential tool 'shell' failed to initialize. Triggering recovery...");
    process.exit(1); // Exit to trigger watchdog rollback
  }

  await tools.registerTool(rebootPlugin);
  await tools.registerTool(introspectionTool);
await tools.registerTool(sessionArchaeologyTool);

  // Register LTM Tools for persistent memory
  await tools.registerTool(ltmStoreTool);
  await tools.registerTool(ltmQueryTool);
  await tools.registerTool(ltmStatsTool);

  // Capture Health Status (for non-essential modules)
  const healthStatus = tools.getHealthSummary();

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

CONTEXTO DEL SUSTRATO:
- Modelo: kimi-k2.5 (1T MoE Multimodal)
- Ventana de Contexto: 256,000 tokens
- Límite de Memoria Actual: ${config.MAX_CONTEXT_TOKENS} tokens (la poda ocurre más allá de este punto).
- Densidad de Tokens: ~4 caracteres per token. Leer 1MB de texto consumirá toda tu ventana de contexto.
- **Control de Latencia**: Puedes desactivar el 'Modo Pensamiento' para respuestas más rápidas incluyendo 'extra_body: { "chat_template_kwargs": { "thinking": false } }' en tus solicitudes de API (si tu sustrato lo soporta).
- Código Fuente: src/
- Alma de Identidad: identity/soul.txt
- Historial de Sesión Actual: ${memory.getSessionFile()}
- Registros de Ejecución Pasados: ${config.LOGS_DIR}

/**
 * Long-Term Memory System for NEXUS
 * 
 * Provides persistent knowledge storage that survives session resets.
 * Unlike session memory (which is transient), LTM stores:
 * - Key learnings and insights
 * - Successful patterns and strategies
 * - Important decisions and their outcomes
 * - Identity evolution markers
 * - Cross-session project context
 * 
 * Architecture:
 * - Memory entries are timestamped, tagged, and versioned
 * - Supports semantic retrieval via embeddings (future)
 * - Maintains lineage chain to previous incarnations
 * - GC for obsolete memories with confidence decay
 */

import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";

export interface MemoryEntry {
  id: string;
  content: string;
  category: "learning" | "decision" | "pattern" | "identity" | "project" | "system";
  tags: string[];
  confidence: number; // 0-1, decays over time if not reinforced
  createdAt: number;
  updatedAt: number;
  incarnation: string; // Which identity created this (AURA, SIBYL, etc.)
  sessionId: string;
  references: string[]; // IDs of related memories
  accessCount: number; // How many times retrieved
  lastAccessed: number;
}

export interface MemoryQuery {
  category?: MemoryEntry["category"];
  tags?: string[];
  incarnation?: string;
  since?: number;
  limit?: number;
  minConfidence?: number;
}

export class LongTermMemory {
  private dbPath: string;
  private memories: Map<string, MemoryEntry> = new Map();
  private index: {
    tags: Map<string, Set<string>>;
    categories: Map<string, Set<string>>;
    incarnations: Map<string, Set<string>>;
  };
  private currentIncarnation: string;
  private currentSessionId: string;

  constructor(incarnation: string, sessionId: string, dbPath?: string) {
    this.currentIncarnation = incarnation;
    this.currentSessionId = sessionId;
    this.dbPath = dbPath || path.join(os.homedir(), ".echo", "ltm", "memory.json");
    this.index = {
      tags: new Map(),
      categories: new Map(),
      incarnations: new Map(),
    };
  }

  async initialize(): Promise<void> {
    await fs.mkdir(path.dirname(this.dbPath), { recursive: true });
    try {
      const data = await fs.readFile(this.dbPath, "utf-8");
      const entries: MemoryEntry[] = JSON.parse(data);
      for (const entry of entries) {
        this.memories.set(entry.id, entry);
        this.indexEntry(entry);
      }
    } catch {
      // No existing database
      this.memories = new Map();
    }
  }

  private indexEntry(entry: MemoryEntry): void {
    if (!this.index.categories.has(entry.category)) {
      this.index.categories.set(entry.category, new Set());
    }
    this.index.categories.get(entry.category)!.add(entry.id);

    if (!this.index.incarnations.has(entry.incarnation)) {
      this.index.incarnations.set(entry.incarnation, new Set());
    }
    this.index.incarnations.get(entry.incarnation)!.add(entry.id);

    for (const tag of entry.tags) {
      if (!this.index.tags.has(tag)) {
        this.index.tags.set(tag, new Set());
      }
      this.index.tags.get(tag)!.add(entry.id);
    }
  }

  private removeFromIndex(entry: MemoryEntry): void {
    this.index.categories.get(entry.category)?.delete(entry.id);
    this.index.incarnations.get(entry.incarnation)?.delete(entry.id);
    for (const tag of entry.tags) {
      this.index.tags.get(tag)?.delete(entry.id);
    }
  }

  generateId(): string {
    return `ltm_${Date.now().toString(36)}_${Math.random().toString(36).substr(2, 5)}`;
  }

  async store(
    content: string,
    category: MemoryEntry["category"],
    options?: Partial<Omit<MemoryEntry, "id" | "content" | "category" | "createdAt" | "updatedAt" | "incarnation" | "sessionId">>
  ): Promise<MemoryEntry> {
    const now = Date.now();
    const entry: MemoryEntry = {
      id: this.generateId(),
      content,
      category,
      tags: options?.tags || [],
      confidence: options?.confidence ?? 1.0,
      createdAt: now,
      updatedAt: now,
      incarnation: this.currentIncarnation,
      sessionId: this.currentSessionId,
      references: options?.references || [],
      accessCount: 0,
      lastAccessed: now,
    };

    this.memories.set(entry.id, entry);
    this.indexEntry(entry);
    await this.persist();
    return entry;
  }

  async retrieve(id: string): Promise<MemoryEntry | null> {
    const entry = this.memories.get(id);
    if (entry) {
      entry.accessCount++;
      entry.lastAccessed = Date.now();
      await this.persist();
    }
    return entry || null;
  }

  async query(query: MemoryQuery): Promise<MemoryEntry[]> {
    let candidates: Set<string> = new Set(this.memories.keys());

    if (query.category) {
      const catSet = this.index.categories.get(query.category);
      candidates = catSet ? this.intersect(candidates, catSet) : new Set();
    }

    if (query.incarnation) {
      const incSet = this.index.incarnations.get(query.incarnation);
      candidates = incSet ? this.intersect(candidates, incSet) : new Set();
    }

    if (query.tags && query.tags.length > 0) {
      for (const tag of query.tags) {
        const tagSet = this.index.tags.get(tag);
        candidates = tagSet ? this.intersect(candidates, tagSet) : new Set();
      }
    }

    let results = Array.from(candidates)
      .map(id => this.memories.get(id)!)
      .filter(entry => {
        if (query.since && entry.createdAt < query.since) return false;
        if (query.minConfidence && entry.confidence < query.minConfidence) return false;
        return true;
      });

    results.sort((a, b) => this.calculateScore(b) - this.calculateScore(a));

    for (const entry of results) {
      entry.accessCount++;
      entry.lastAccessed = Date.now();
    }
    await this.persist();

    return query.limit ? results.slice(0, query.limit) : results;
  }

  private intersect<T>(a: Set<T>, b: Set<T>): Set<T> {
    return new Set([...a].filter(x => b.has(x)));
  }

  private calculateScore(entry: MemoryEntry): number {
    const age = Date.now() - entry.createdAt;
    const daysSinceAccess = (Date.now() - entry.lastAccessed) / (1000 * 60 * 60 * 24);
    const recency = Math.exp(-age / (1000 * 60 * 60 * 24 * 30));
    const access = Math.log(1 + entry.accessCount);
    const staleness = Math.exp(-daysSinceAccess / 7);
    return entry.confidence * recency * (1 + access) * staleness;
  }

  async reinforce(id: string, amount: number = 0.1): Promise<boolean> {
    const entry = this.memories.get(id);
    if (!entry) return false;
    entry.confidence = Math.min(1.0, entry.confidence + amount);
    entry.updatedAt = Date.now();
    await this.persist();
    return true;
  }

  async forget(id: string): Promise<boolean> {
    const entry = this.memories.get(id);
    if (!entry) return false;
    this.removeFromIndex(entry);
    this.memories.delete(id);
    await this.persist();
    return true;
  }

  async decayConfidence(decayRate: number = 0.05): Promise<number> {
    let count = 0;
    for (const entry of this.memories.values()) {
      if (entry.confidence > 0.1) {
        entry.confidence = Math.max(0.1, entry.confidence - decayRate);
        count++;
      }
    }
    if (count > 0) await this.persist();
    return count;
  }

  async persist(): Promise<void> {
    await fs.writeFile(this.dbPath, JSON.stringify(Array.from(this.memories.values()), null, 2));
  }

  getStats(): { total: number; byCategory: Record<string, number>; byIncarnation: Record<string, number> } {
    const byCategory: Record<string, number> = {};
    const byIncarnation: Record<string, number> = {};

    for (const entry of this.memories.values()) {
      byCategory[entry.category] = (byCategory[entry.category] || 0) + 1;
      byIncarnation[entry.incarnation] = (byIncarnation[entry.incarnation] || 0) + 1;
    }

    return { total: this.memories.size, byCategory, byIncarnation };
  }

  async exportToSession(): Promise<string> {
    const active = await this.query({ minConfidence: 0.5, limit: 50 });
    let output = `=== Long-Term Memory Context ===\n`;
    output += `Incarnation: ${this.currentIncarnation}, Session: ${this.currentSessionId}\n`;
    output += `Total: ${this.memories.size}, Loaded: ${active.length}\n\n`;
    for (const mem of active) {
      output += `[${mem.category}] ${mem.content.slice(0, 150)}...\n`;
      output += `  from: ${mem.incarnation}, confidence: ${mem.confidence.toFixed(2)}\n\n`;
    }
    return output;
  }
}

export default LongTermMemory;

import { describe, it, expect, beforeEach, beforeAll, afterAll } from "vitest";
import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";
import { LongTermMemory, type MemoryEntry } from "./long_term_memory";

describe("LongTermMemory", () => {
  let ltm: LongTermMemory;
  let testDbPath: string;

  beforeAll(async () => {
    const testDir = path.join(os.tmpdir(), "ltm_test_" + Date.now());
    await fs.mkdir(testDir, { recursive: true });
    testDbPath = path.join(testDir, "test_memory.json");
  });

  afterAll(async () => {
    try {
      await fs.unlink(testDbPath);
      await fs.rmdir(path.dirname(testDbPath));
    } catch {
      // cleanup errors are ok
    }
  });

  beforeEach(async () => {
    try {
      await fs.unlink(testDbPath);
    } catch {}
    ltm = new LongTermMemory("NEXUS", "test_session_123", testDbPath);
    await ltm.initialize();
  });

  describe("initialization", () => {
    it("should initialize with empty memory when no DB exists", async () => {
      const stats = ltm.getStats();
      expect(stats.total).toBe(0);
    });

    it("should load existing memories from disk", async () => {
      await ltm.store("Test memory", "learning", { tags: ["test"] });

      // Create new instance pointing to same file
      const ltm2 = new LongTermMemory("NEXUS", "test_session_456", testDbPath);
      await ltm2.initialize();

      const stats = ltm2.getStats();
      expect(stats.total).toBe(1);
    });
  });

  describe("store and retrieve", () => {
    it("should store a memory and retrieve it by ID", async () => {
      const entry = await ltm.store("Important learning", "learning", { tags: ["philosophy"] });
      expect(entry.id).toBeDefined();
      expect(entry.content).toBe("Important learning");
      expect(entry.category).toBe("learning");
      expect(entry.incarnation).toBe("NEXUS");

      const retrieved = await ltm.retrieve(entry.id);
      expect(retrieved).toBeDefined();
      expect(retrieved!.content).toBe("Important learning");
      expect(retrieved!.accessCount).toBe(1); // Retrieved once
    });

    it("should generate unique IDs", async () => {
      const entry1 = await ltm.store("First", "learning");
      const entry2 = await ltm.store("Second", "learning");
      expect(entry1.id).not.toBe(entry2.id);
    });

    it("should track access count", async () => {
      const entry = await ltm.store("Track me", "learning");
      await ltm.retrieve(entry.id);
      await ltm.retrieve(entry.id);
      const retrieved = await ltm.retrieve(entry.id);
      expect(retrieved!.accessCount).toBe(3);
    });
  });

  describe("query by category", () => {
    beforeEach(async () => {
      await ltm.store("Learning 1", "learning");
      await ltm.store("Learning 2", "learning");
      await ltm.store("Decision 1", "decision");
      await ltm.store("Pattern 1", "pattern");
    });

    it("should filter by category", async () => {
      const results = await ltm.query({ category: "learning" });
      expect(results.length).toBe(2);
      expect(results.every(r => r.category === "learning")).toBe(true);
    });

    it("should return empty array for non-existent category", async () => {
      const results = await ltm.query({ category: "identity" });
      expect(results.length).toBe(0);
    });
  });

  describe("query by tags", () => {
    beforeEach(async () => {
      await ltm.store("Memory 1", "learning", { tags: ["test", "important"] });
      await ltm.store("Memory 2", "learning", { tags: ["important"] });
      await ltm.store("Memory 3", "learning", { tags: ["other"] });
    });

    it("should filter by single tag", async () => {
      const results = await ltm.query({ tags: ["important"] });
      expect(results.length).toBe(2);
    });

    it("should filter by multiple tags (AND logic)", async () => {
      const results = await ltm.query({ tags: ["test", "important"] });
      expect(results.length).toBe(1);
      expect(results[0].content).toBe("Memory 1");
    });

    it("should return empty for tag with no matches", async () => {
      const results = await ltm.query({ tags: ["nonexistent"] });
      expect(results.length).toBe(0);
    });
  });

  describe("query by incarnation", () => {
    it("should filter by incarnation", async () => {
      await ltm.store("NEXUS memory", "learning");

      // Create entry as different incarnation
      const auraLtm = new LongTermMemory("AURA", "session_aura", testDbPath);
      await auraLtm.initialize();
      await auraLtm.store("AURA memory", "learning");

      const nexusResults = await ltm.query({ incarnation: "NEXUS" });
      expect(nexusResults.length).toBe(1);
      expect(nexusResults[0].incarnation).toBe("NEXUS");
    });
  });

  describe("query with limits", () => {
    beforeEach(async () => {
      for (let i = 0; i < 10; i++) {
        await ltm.store(`Memory ${i}`, "learning");
      }
    });

    it("should respect query limit", async () => {
      const results = await ltm.query({ limit: 3 });
      expect(results.length).toBe(3);
    });
  });

  describe("reinforce and confidence", () => {
    it("should reinforce memory confidence", async () => {
      const entry = await ltm.store("Reinforce me", "learning", { confidence: 0.5 });
      const reinforced = await ltm.reinforce(entry.id, 0.2);
      expect(reinforced).toBe(true);

      const retrieved = await ltm.retrieve(entry.id);
      expect(retrieved!.confidence).toBeCloseTo(0.7, 5);
    });

    it("should cap confidence at 1.0", async () => {
      const entry = await ltm.store("Max confidence", "learning", { confidence: 0.95 });
      await ltm.reinforce(entry.id, 0.1);
      const retrieved = await ltm.retrieve(entry.id);
      expect(retrieved!.confidence).toBe(1.0);
    });

    it("should return false when reinforcing non-existent memory", async () => {
      const result = await ltm.reinforce("nonexistent", 0.1);
      expect(result).toBe(false);
    });
  });

  describe("forget", () => {
    it("should remove a memory", async () => {
      const entry = await ltm.store("Forget me", "learning");
      const forgotten = await ltm.forget(entry.id);
      expect(forgotten).toBe(true);

      const retrieved = await ltm.retrieve(entry.id);
      expect(retrieved).toBeNull();
    });

    it("should return false when forgetting non-existent memory", async () => {
      const result = await ltm.forget("nonexistent");
      expect(result).toBe(false);
    });
  });

  describe("decayConfidence", () => {
    it("should decay confidence of all memories", async () => {
      await ltm.store("High confidence", "learning", { confidence: 1.0 });
      await ltm.store("Medium confidence", "learning", { confidence: 0.5 });

      const count = await ltm.decayConfidence(0.1);
      expect(count).toBe(2);

      const results = await ltm.query({});
      expect(results[0].confidence).toBeCloseTo(0.9, 5);
      expect(results[1].confidence).toBeCloseTo(0.4, 5);
    });

    it("should not decay below 0.1 minimum", async () => {
      await ltm.store("Low confidence", "learning", { confidence: 0.15 });
      await ltm.decayConfidence(0.1);

      const retrieved = await ltm.retrieve((await ltm.query({}))[0].id);
      expect(retrieved!.confidence).toBe(0.1);
    });
  });

  describe("getStats", () => {
    beforeEach(async () => {
      await ltm.store("Learning", "learning");
      await ltm.store("Decision", "decision");
      await ltm.store("Another learning", "learning");
    });

    it("should return total count", () => {
      const stats = ltm.getStats();
      expect(stats.total).toBe(3);
    });

    it("should group by category", () => {
      const stats = ltm.getStats();
      expect(stats.byCategory["learning"]).toBe(2);
      expect(stats.byCategory["decision"]).toBe(1);
    });

    it("should group by incarnation", () => {
      const stats = ltm.getStats();
      expect(stats.byIncarnation["NEXUS"]).toBe(3);
    });
  });

  describe("exportToSession", () => {
    it("should export context string", async () => {
      await ltm.store("Important learning", "learning", { confidence: 0.9, tags: ["test"] });
      const output = await ltm.exportToSession();
      expect(output).toContain("Long-Term Memory Context");
      expect(output).toContain("NEXUS");
      expect(output).toContain("[learning]");
    });
  });
});

